import{_ as t,o as r,c as a,a2 as d}from"./chunks/framework.DeNJmwJc.js";const u=JSON.parse('{"title":"Chapter 38 — Buffers","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/38-buffers.md","filePath":"chapters/38-buffers.md"}'),o={name:"chapters/38-buffers.md"};function i(s,e,l,c,n,f){return r(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="chapter-38-—-buffers" tabindex="-1">Chapter 38 — Buffers <a class="header-anchor" href="#chapter-38-—-buffers" aria-label="Permalink to &quot;Chapter 38 — Buffers&quot;">​</a></h1><blockquote><p><em>&quot;Every file you open is a buffer. Manage them well.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>A <strong>buffer</strong> is a file loaded into memory for editing.</p><p>Unlike windows or tabs, buffers exist even when not visible.</p><hr><h1 id="buffer-commands" tabindex="-1">Buffer Commands <a class="header-anchor" href="#buffer-commands" aria-label="Permalink to &quot;Buffer Commands&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:ls</code> or <code>:buffers</code></td><td>List all buffers</td></tr><tr><td><code>:bn</code></td><td>Next buffer</td></tr><tr><td><code>:bp</code></td><td>Previous buffer</td></tr><tr><td><code>:b3</code></td><td>Go to buffer number 3</td></tr><tr><td><code>:b file</code></td><td>Go to buffer by filename</td></tr><tr><td><code>:bd</code></td><td>Delete (close) buffer</td></tr><tr><td><code>:e file</code></td><td>Open file in new buffer</td></tr></tbody></table><hr><h1 id="key-mappings" tabindex="-1">Key Mappings <a class="header-anchor" href="#key-mappings" aria-label="Permalink to &quot;Key Mappings&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+^</code></td><td>Toggle between last two buffers</td></tr><tr><td><code>:bn</code></td><td>Next buffer</td></tr><tr><td><code>:bp</code></td><td>Previous buffer</td></tr><tr><td><code>:bdelete</code></td><td>Close current buffer</td></tr><tr><td><code>:bufdo</code></td><td>Run command on all buffers</td></tr></tbody></table><hr><h1 id="buffer-states" tabindex="-1">Buffer States <a class="header-anchor" href="#buffer-states" aria-label="Permalink to &quot;Buffer States&quot;">​</a></h1><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:ls</span></span></code></pre></div><p>Shows all buffers with their state:</p><ul><li><code>%</code> — Current buffer</li><li><code>#</code> — Alternate buffer</li><li><code>a</code> — Active (visible)</li><li><code>h</code> — Hidden</li><li><code>u</code> — Unlisted</li><li><code>+</code> — Modified</li></ul><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li>Buffers are files loaded in memory.</li><li><code>:ls</code> lists buffers, <code>:bn</code>/:bp` navigate.</li><li><code>Ctrl+^</code> toggles between last two buffers.</li><li><code>:bd</code> closes a buffer.</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open three files, list buffers with <code>:ls</code>.</li><li>Navigate buffers with <code>:bn</code> and <code>:bp</code>.</li><li>Use <code>Ctrl+^</code> to toggle.</li><li>Delete a buffer with <code>:bd</code>.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./39-windows.html"><strong>Chapter 39 — Windows</strong></a></p><p>Split your workspace into multiple windows.</p>',29)])])}const b=t(o,[["render",i]]);export{u as __pageData,b as default};
